#include<iostream>
#include<cstdio>
#include<algorithm>
using namespace std;

int w[1003], v[1003], dp[30][30004];

int main() {
	int n, m;
	cin >> m >> n;
	for(int i = 1; i <= n; i++)
	{
		cin >> w[i] >> v[i];
	}
	for(int i = 1; i <= m; i++)
		dp[0][i] = 0;
	for(int i = 1; i <= n; i++)
		for(int j = 0; j <= m; j++)
		{
			dp[i][j] = dp[i - 1][j];
			if(j >= w[i]) dp[i][j] = max(dp[i][j], dp[i - 1][j - w[i]] + v[i] * w[i]);
		}
	cout << dp[n][m];
    return 0;
}
